import{_ as a,o as d,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const z=JSON.parse('{"title":"Nastavení stránky","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Page/page-settings.md","filePath":"cs-CZ/Page/page-settings.md","lastUpdated":1781962217000}'),r={name:"cs-CZ/Page/page-settings.md"};function n(i,t,l,p,s,c){return d(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="nastaveni-stranky" tabindex="-1">Nastavení stránky <a class="header-anchor" href="#nastaveni-stranky" aria-label="Permalink to &quot;Nastavení stránky&quot;">​</a></h1><p>Nastavení stránky řídí vzhled webu, výchozí nastavení upload stránky, obrázky pozadí a vzhled administrace.</p><h2 id="globalni-nastaveni" tabindex="-1">Globální nastavení <a class="header-anchor" href="#globalni-nastaveni" aria-label="Permalink to &quot;Globální nastavení&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Volba</th><th>Účel</th></tr></thead><tbody><tr><td>Titulek webu</td><td>Titulek zobrazený na kartě prohlížeče.</td></tr><tr><td>Ikona webu</td><td>Malá ikona zobrazená na kartě prohlížeče.</td></tr><tr><td>Název ImgBed</td><td>Název zobrazený na frontendových stránkách.</td></tr><tr><td>Logo ImgBed</td><td>Obrázek loga zobrazený na frontendových stránkách.</td></tr><tr><td>Odkaz loga</td><td>URL otevřený po kliknutí na logo nebo avatar.</td></tr><tr><td>Interval střídání pozadí</td><td>Interval rotace více pozadí v milisekundách. <code>60000</code> znamená 60 sekund.</td></tr><tr><td>Průhlednost pozadí</td><td>Průhlednost obrázku pozadí od <code>0</code> do <code>1</code>. Nižší hodnoty jsou světlejší.</td></tr><tr><td>Výchozí URL prefix</td><td>Prefix používaný při generování odkazů obrázků. Prázdné znamená aktuální doménu webu.</td></tr></tbody></table><h2 id="klientska-nastaveni" tabindex="-1">Klientská nastavení <a class="header-anchor" href="#klientska-nastaveni" aria-label="Permalink to &quot;Klientská nastavení&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Volba</th><th>Účel</th></tr></thead><tbody><tr><td>Oznámení</td><td>Oznámení zobrazené nahoře na upload stránce. HTML je podporováno.</td></tr><tr><td>Výchozí upload kanál</td><td>Kanál vybraný ve výchozím stavu na upload stránce. Lze zvolit i Smart Dispatch.</td></tr><tr><td>Výchozí upload adresář</td><td>Výchozí adresář pro upload, například <code>/user/</code>. Prázdné nebo <code>/</code> znamená root.</td></tr><tr><td>Výchozí metoda pojmenování</td><td>Výchozí strategie generování názvu souboru po uploadu. Viz níže.</td></tr><tr><td>Výchozí převod na WebP</td><td>Před uploadem převádí obrázky na WebP.</td></tr><tr><td>Výchozí komprese</td><td>Před uploadem komprimuje obrázky lokálně v prohlížeči.</td></tr><tr><td>Výchozí práh komprese</td><td>Automaticky komprimuje, když obrázek překročí tuto velikost v MB.</td></tr><tr><td>Výchozí cílová velikost</td><td>Cílová velikost souboru po kompresi v MB.</td></tr><tr><td>Pozadí přihlašovací stránky</td><td>Obrázek pozadí pro přihlášení uživatele.</td></tr><tr><td>Pozadí upload stránky</td><td>Obrázek pozadí pro upload stránku.</td></tr><tr><td>Odkaz portálu v patičce</td><td>URL otevřený tlačítkem portálu v patičce.</td></tr><tr><td>Skrýt patičku</td><td>Po zapnutí skryje frontendovou patičku.</td></tr></tbody></table><h2 id="nastaveni-administrace" tabindex="-1">Nastavení administrace <a class="header-anchor" href="#nastaveni-administrace" aria-label="Permalink to &quot;Nastavení administrace&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Volba</th><th>Účel</th></tr></thead><tbody><tr><td>Pozadí přihlášení administrátora</td><td>Obrázek pozadí pro přihlášení administrátora.</td></tr><tr><td>Pozadí administrace</td><td>Obrázek pozadí pro administrační stránky. Použijte jeden URL obrázku nebo více URL.</td></tr><tr><td>Režim načítání obrázků</td><td>Režim náhledu v seznamu souborů administrace. Original načítá původní obrázky. Smart loading preferuje miniatury pro veřejné obrázky a originály pro omezené obrázky.</td></tr><tr><td>Zdroj miniatur</td><td>Služba pro generování miniatur: wsrv.nl, Cloudflare Image Resizing nebo WordPress Photon. Cloudflare Image Resizing musí být v Cloudflare zapnuté před výběrem.</td></tr><tr><td>Live2D widget</td><td>Zobrazí postavu Live2D v administraci.</td></tr><tr><td>Efekt ohňostroje při kliknutí</td><td>Zobrazí efekt ohňostroje při kliknutí na stránku.</td></tr><tr><td>Hvězdná stopa kurzoru</td><td>Zobrazí hvězdnou stopu při pohybu myši.</td></tr></tbody></table><h2 id="formaty-obrazku-pozadi" tabindex="-1">Formáty obrázků pozadí <a class="header-anchor" href="#formaty-obrazku-pozadi" aria-label="Permalink to &quot;Formáty obrázků pozadí&quot;">​</a></h2><p>Pozadí přihlašovací stránky, upload stránky a přihlášení administrátora podporují:</p><table tabindex="0"><thead><tr><th>Hodnota</th><th>Efekt</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Použije rotaci tapet Bing.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Střídá více obrázků.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Použije jeden obrázek pozadí.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Použije odkaz Random Image API. Vlastní Random Image API můžete nastavit v Dalších nastaveních a vložit sem vygenerovaný odkaz jako jedno pozadí.</td></tr></tbody></table><p>Pozadí administrace podporuje URL obrázků. Více URL lze oddělit anglickými čárkami podle nápovědy na stránce. Prázdné pole znamená výchozí pozadí.</p><h2 id="vychozi-metoda-pojmenovani" tabindex="-1">Výchozí metoda pojmenování <a class="header-anchor" href="#vychozi-metoda-pojmenovani" aria-label="Permalink to &quot;Výchozí metoda pojmenování&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metoda</th><th>Výsledek</th></tr></thead><tbody><tr><td>Default</td><td>Časově-náhodný prefix + původní název souboru, například <code>1760000000000_cat.png</code>.</td></tr><tr><td>Pouze prefix</td><td>Časově-náhodný prefix a přípona, například <code>1760000000000.png</code>.</td></tr><tr><td>Pouze původní název</td><td>Zachová původní název, například <code>cat.png</code>. Při duplicitě ImgBed přidá <code>(1)</code>, <code>(2)</code> a tak dále.</td></tr><tr><td>Krátký odkaz</td><td>Použije 8znakové krátké ID a příponu, například <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=a(r,[["render",n]]);export{z as __pageData,u as default};
